47	  constant OffsetBits_c   : integer     := psi_fix_size(in_fmt_g) - IndexBits_c;
48	  constant RemFmt_c       : psi_fix_fmt_t := (0, OffsetBits_c - in_fmt_g.F, in_fmt_g.F);
49	  constant RemFmtSigned_c : psi_fix_fmt_t := (1, RemFmt_c.I - 1, RemFmt_c.F);
50	  constant IdxFmt_c       : psi_fix_fmt_t := (0, in_fmt_g.S + in_fmt_g.I, in_fmt_g.F - RemFmt_c.F - RemFmt_c.I);
51	  constant IntFmt_c       : psi_fix_fmt_t := (1, RemFmt_c.I + grad_fmt_g.I + 1, RemFmt_c.F + grad_fmt_g.F);
52	  constant AddFmt_c       : psi_fix_fmt_t := (max(IntFmt_c.S, offs_fmt_g.S), max(IntFmt_c.I, offs_fmt_g.I) + 1, max(IntFmt_c.F, offs_fmt_g.F));
53	
54	  subtype OffsRng_c is natural range psi_fix_size(offs_fmt_g) - 1 downto 0;
55	  subtype GradRng_c is natural range psi_fix_size(grad_fmt_g) + OffsRng_c'high downto OffsRng_c'high + 1;
56	
57	  -- types
58	  type Rem_t is array (natural range <>) of std_logic_vector(psi_fix_size(RemFmt_c) - 1 downto 0);
59	  type Offs_t is array (natural range <>) of std_logic_vector(psi_fix_size(offs_fmt_g) - 1 downto 0);
60	
61	  -- Two process method
62	  type two_process_r is record
63	    Vld       : std_logic_vector(0 to 6);
64	    In_0      : std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
65	    TblIdx_1  : std_logic_vector(psi_fix_size(IdxFmt_c) - 1 downto 0);
66	    Offs      : Offs_t(3 to 4);
67	    Grad_3    : std_logic_vector(psi_fix_size(grad_fmt_g) - 1 downto 0);
68	    Reminder  : Rem_t(1 to 3);
69	    GradVal_4 : std_logic_vector(psi_fix_size(IntFmt_c) - 1 downto 0);
70	    Add_5     : std_logic_vector(psi_fix_size(AddFmt_c) - 1 downto 0);
71	    Out_6     : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
72	  end record;
73	  signal r, r_next : two_process_r;
74	
75	begin
76	  --------------------------------------------
77	  -- Combinatorial Process
78	  --------------------------------------------
79	  p_comb : process(r, vld_i, dat_i, data_table_i)
