81	  begin
82	    -- *** Hold variables stable ***
83	    v := r;
84	
85	    -- *** Pipe Handling ***
86	    v.Vld(v.Vld'low + 1 to v.Vld'high)                := r.Vld(r.Vld'low to r.Vld'high - 1);
87	    v.Reminder(v.Reminder'low + 1 to v.Reminder'high) := r.Reminder(r.Reminder'low to r.Reminder'high - 1);
88	    v.Offs(v.Offs'low + 1 to v.Offs'high)             := r.Offs(r.Offs'low to r.Offs'high - 1);
89	
90	    -- *** Stage 0 ***
91	    -- Input Registers
92	    v.Vld(0) := vld_i;
93	    v.In_0   := dat_i;
94	
95	    -- *** Stage 1 ***
96	    -- Index Calculation
97	    v.TblIdx_1                        := psi_fix_resize(r.In_0, in_fmt_g, IdxFmt_c);
98	    v.Reminder(1)                     := psi_fix_resize(r.In_0, in_fmt_g, RemFmt_c);
99	    -- Inverts MSB to have a signed offset
100	    v.Reminder(1)(v.Reminder(1)'high) := not v.Reminder(1)(v.Reminder(1)'high);
101	
102	    -- *** Stage 2 ***
103	    -- Reserved for Table output registers
104	
105	    -- *** Stage 3 ***
106	    -- Registering of Table outputs
107	    v.Offs(3) := data_table_i(OffsRng_c);
108	    v.Grad_3  := data_table_i(GradRng_c);
109	
110	    -- *** Stage 4 ***
111	    -- Multiplication
112	    v.GradVal_4 := psi_fix_mult(r.Grad_3, grad_fmt_g,
113	                              r.Reminder(3), RemFmtSigned_c, -- Reinterpret as signed, equal to python MSB inversion
114	                              IntFmt_c);
115	
116	    -- *** Stage 5 ***
117	    -- Addition (at full precision and without round/sat to fit into DSP slie)
118	    v.Add_5 := psi_fix_add(r.Offs(4), offs_fmt_g,
119	                         r.GradVal_4, IntFmt_c,
120	                         AddFmt_c, psi_fix_trunc, psi_fix_wrap);
121	
122	    -- *** Stage 6 ***
123	    -- Output rounding and saturation
124	    v.Out_6 := psi_fix_resize(r.Add_5, AddFmt_c,
125	                            out_fmt_g, psi_fix_round, psi_fix_sat);
126	
127	    -- *** Outputs ***
128	    addr_table_o <= r.TblIdx_1;
129	    vld_o        <= r.Vld(6);
130	    dat_o        <= r.Out_6;
131	
132	    -- *** Assign to signal ***
133	    r_next <= v;
134	  end process;
